def do_antitarget(targets, access=None, avg_bin_size=150000, min_bin_size=None):
    if not min_bin_size:
        min_bin_size = 2 * int(avg_bin_size * (2**MIN_REF_COVERAGE))
    return get_antitargets(targets, access, avg_bin_size, min_bin_size)

def guess_chromosome_regions(targets, telomere_size):
    endpoints = [subarr.end.iat[-1] for _c, subarr in targets.by_chromosome()]
    whole_chroms = GA.from_columns(
        {
            "chromosome": targets.chromosome.drop_duplicates(),
            "start": telomere_size,
            "end": endpoints,
        }
    )
    return whole_chroms

def do_coverage(
    bed_fname, bam_fname, by_count=False, min_mapq=0, processes=1, fasta=None
):
    if not samutil.ensure_bam_sorted(bam_fname, fasta=fasta):
        raise RuntimeError(f"BAM file {bam_fname} must be sorted by coordinates")
    samutil.ensure_bam_index(bam_fname)
    # ENH: count importers.TOO_MANY_NO_COVERAGE & warn
    cnarr = interval_coverages(
        bed_fname, bam_fname, by_count, min_mapq, processes, fasta
    )
    return cnarr

def interval_coverages_count(bed_fname, bam_fname, min_mapq, procs=1, fasta=None):
    regions = tabio.read_auto(bed_fname)
    if procs == 1:
        bamfile = pysam.AlignmentFile(bam_fname, "rb", reference_filename=fasta)
        for chrom, subregions in regions.by_chromosome():
            logging.info(
                "Processing chromosome %s of %s", chrom, os.path.basename(bam_fname)
            )
            for count, row in _rdc_chunk(bamfile, subregions, min_mapq):
                yield [count, row]
    else:
        with futures.ProcessPoolExecutor(procs) as pool:
            args_iter = (
                (bam_fname, subr, min_mapq, fasta)
                for _c, subr in regions.by_chromosome()
            )
            for chunk in pool.map(_rdc, args_iter):
                for count, row in chunk:
                    yield [count, row]

def _rdc(args):
    return list(_rdc_chunk(*args))

def _rdc_chunk(bamfile, regions, min_mapq, fasta=None):
    if isinstance(bamfile, str):
        bamfile = pysam.AlignmentFile(bamfile, "rb", reference_filename=fasta)
    for chrom, start, end, gene in regions.coords(["gene"]):
        yield region_depth_count(bamfile, chrom, start, end, gene, min_mapq)

def region_depth_count(bamfile, chrom, start, end, gene, min_mapq):
    def filter_read(read):
        return not (
            read.is_duplicate
            or read.is_secondary
            or read.is_unmapped
            or read.is_qcfail
            or read.mapq < min_mapq
        )
    count = 0
    bases = 0
    for read in bamfile.fetch(reference=chrom, start=start, end=end):
        if filter_read(read):
            count += 1
            # Only count the bases aligned to the region
            bases += sum(1 for p in read.positions if start <= p < end)
    depth = bases / (end - start) if end > start else 0
    row = (
        chrom,
        start,
        end,
        gene,
        math.log(depth, 2) if depth else NULL_LOG2_COVERAGE,
        depth,
    )
    return count, row

def bedcov(bed_fname, bam_fname, min_mapq, fasta=None):
    # Count bases in each region; exclude low-MAPQ reads
    cmd = [bed_fname, bam_fname]
    if min_mapq and min_mapq > 0:
        cmd.extend(["-Q", str(min_mapq)])
    if fasta:
        cmd.extend(["--reference", fasta])
    try:
        raw = pysam.bedcov(*cmd, split_lines=False)
    except pysam.SamtoolsError as exc:
        raise ValueError(
            f"Failed processing {bam_fname!r} coverages in {bed_fname!r} regions. "
            f"PySAM error: {exc}"
        ) from exc
    if not raw:
        raise ValueError(
            f"BED file {bed_fname!r} chromosome names don't match any in "
            f"BAM file {bam_fname!r}"
        )
    columns = detect_bedcov_columns(raw)
    table = pd.read_csv(StringIO(raw), sep="\t", names=columns, usecols=columns)
    return table

def detect_bedcov_columns(text):
    firstline = text[: text.index("\n")]
    tabcount = firstline.count("\t")
    if tabcount < 3:
        raise RuntimeError(f"Bad line from bedcov:\n{firstline!r}")
    if tabcount == 3:
        return ["chromosome", "start", "end", "basecount"]
    if tabcount == 4:
        return ["chromosome", "start", "end", "gene", "basecount"]
    # Input BED has arbitrary columns after 'gene' -- ignore them
    fillers = [f"_{i}" for i in range(1, tabcount - 3)]
    return ["chromosome", "start", "end", "gene"] + fillers + ["basecount"]

def filter_read(read):
        return not (
            read.is_duplicate
            or read.is_secondary
            or read.is_unmapped
            or read.is_qcfail
            or read.mapq < min_mapq
        )

def infer_sexes(cnn_fnames, is_haploid_x, diploid_parx_genome):
    sexes = {}
    for fname in cnn_fnames:
        cnarr = read_cna(fname)
        if cnarr:
            is_xx = cnarr.guess_xx(is_haploid_x, diploid_parx_genome)
            if is_xx is not None:
                sexes[cnarr.sample_id] = is_xx
    return sexes

def shift_sex_chroms(cnarr, sexes, ref_flat_logr, is_chr_x, is_chr_y):
    is_xx = sexes.get(cnarr.sample_id)
    cnarr["log2"] += ref_flat_logr
    if is_xx:
        # chrX has same ploidy as autosomes; chrY is just unusable noise
        cnarr[is_chr_y, "log2"] = -1.0  # np.nan is worse
    else:
        # 1/2 #copies of each sex chromosome
        cnarr[is_chr_x | is_chr_y, "log2"] += 1.0

def summarize_info(all_logr, all_depths):
    logging.info("Calculating average bin coverages")
    cvg_centers = np.apply_along_axis(descriptives.biweight_location, 0, all_logr)
    depth_centers = np.apply_along_axis(descriptives.biweight_location, 0, all_depths)
    logging.info("Calculating bin spreads")
    spreads = np.array(
        [
            descriptives.biweight_midvariance(a, initial=i)
            for a, i in zip(all_logr.T, cvg_centers)
        ]
    )
    result = {
        "log2": cvg_centers,
        "depth": depth_centers,
        "spread": spreads,
    }
    # TODO center the resulting log2
    # ref_df = pd.DataFrame.from_dict(ref_columns)
    # ref_cna = CNA.from_columns(ref_columns, {'sample_id': "reference"})
    return result

def get_fasta_stats(cnarr, fa_fname):
    logging.info("Calculating GC and RepeatMasker content in %s ...", fa_fname)
    gc_rm_vals = [
        calculate_gc_lo(subseq) for subseq in fasta_extract_regions(fa_fname, cnarr)
    ]
    gc_vals, rm_vals = zip(*gc_rm_vals)
    return np.asarray(gc_vals, dtype=float), np.asarray(rm_vals, dtype=float)

def fasta_extract_regions(fa_fname, intervals):
    with pyfaidx.Fasta(fa_fname, as_raw=True) as fa_file:
        for chrom, subarr in intervals.by_chromosome():
            logging.info("Extracting sequences from chromosome %s", chrom)
            for _chrom, start, end in subarr.coords():
                yield fa_file[_chrom][int(start) : int(end)]

def match_ref_to_sample(ref_cnarr, samp_cnarr):
    # Assign each bin a unique string ID based on genomic coordinates
    samp_labeled = samp_cnarr.data.set_index(pd.Index(samp_cnarr.coords()))
    ref_labeled = ref_cnarr.data.set_index(pd.Index(ref_cnarr.coords()))
    for dset, name in ((samp_labeled, "sample"), (ref_labeled, "reference")):
        dupes = dset.index.duplicated()
        if dupes.any():
            raise ValueError(
                (
                    "Duplicated genomic coordinates in {} set. Total duplicated regions: {}, starting with:\n"
                    "{}."
                ).format(
                    name,
                    len(dset.index[dupes]),
                    "\n".join(map(str, dset.index[dupes][:10])),
                )
            )
    # Take the reference bins with IDs identical to those in the sample
    ref_matched = ref_labeled.reindex(index=samp_labeled.index)
    # Check for signs that the wrong reference was used
    num_missing = pd.isnull(ref_matched.start).sum()
    if num_missing > 0:
        raise ValueError(
            f"Reference is missing {num_missing} bins found in {samp_cnarr.sample_id}"
        )
    x = ref_cnarr.as_dataframe(
        ref_matched.reset_index(drop=True).set_index(samp_cnarr.data.index)
    )
    return x

def filter_names(names, exclude=("mRNA",)):
    if len(names) > 1:
        ok_names = set(n for n in names if not any(n.startswith(ex) for ex in exclude))
        if ok_names:
            return ok_names
    # Names are not filter-worthy; leave them as they are for now
    return names

def shortest_name(names):
    name = min(filter_names(names), key=len)
    if len(name) > 2 and "|" in name[1:-1]:
        # Split 'DB|accession' and extract the accession sans-DB
        name = name.split("|")[-1]
    return name

def do_access(fa_fname, exclude_fnames=(), min_gap_size=5000, skip_noncanonical=True):
    fa_regions = get_regions(fa_fname)
    if skip_noncanonical:
        fa_regions = drop_noncanonical_contigs(fa_regions)
    access_regions = GA.from_rows(fa_regions)
    for ex_fname in exclude_fnames:
        excluded = tabio.read(ex_fname, "bed3")
        access_regions = access_regions.subtract(excluded)
    return GA.from_rows(join_regions(access_regions, min_gap_size))

def drop_noncanonical_contigs(region_tups):
    # Avoid a circular import
    from .antitarget import is_canonical_contig_name
    return (tup for tup in region_tups if is_canonical_contig_name(tup[0]))

def get_regions(fasta_fname):
    with open(fasta_fname) as infile:
        chrom = cursor = run_start = None
        for line in infile:
            if line.startswith(">"):
                # Emit the last chromosome's last run, if any
                if run_start is not None:
                    yield log_this(chrom, run_start, cursor)
                # Start new chromosome
                chrom = line.split(None, 1)[0][1:]
                run_start = None
                cursor = 0
                logging.info("%s: Scanning for accessible regions", chrom)
            else:
                line = line.rstrip()
                if "N" in line:
                    if all(c == "N" for c in line):
                        # Shortcut if the line is all N chars
                        if run_start is not None:
                            yield log_this(chrom, run_start, cursor)
                            run_start = None
                    else:
                        # Slow route: line is a mix of N and non-N chars
                        line_chars = np.array(line, dtype="c")
                        n_indices = np.where(line_chars == b"N")[0]
                        # Emit the first block of non-N chars, if any
                        if run_start is not None:
                            yield log_this(chrom, run_start, cursor + n_indices[0])
                        elif n_indices[0] != 0:
                            yield log_this(chrom, cursor, cursor + n_indices[0])
                        # Emit any short intermediate blocks
                        gap_mask = np.diff(n_indices) > 1
                        if gap_mask.any():
                            ok_starts = n_indices[:-1][gap_mask] + 1 + cursor
                            ok_ends = n_indices[1:][gap_mask] + cursor
                            for start, end in zip(ok_starts, ok_ends):
                                yield log_this(chrom, start, end)
                        # Account for any tailing non-N chars
                        if n_indices[-1] + 1 < len(line_chars):
                            run_start = cursor + n_indices[-1] + 1
                        else:
                            run_start = None
                else:
                    if run_start is None:
                        # Start of a new run of non-N characters
                        run_start = cursor
                cursor += len(line)
        # Emit the last run if it's accessible (i.e. not a telomere)
        if run_start is not None:
            yield log_this(chrom, run_start, cursor)

def log_this(chrom, run_start, run_end):
    logging.info(
        "\tAccessible region %s:%d-%d (size %d)",
        chrom,
        run_start,
        run_end,
        run_end - run_start,
    )
    return (chrom, run_start, run_end)

def midsize_file(fnames):
    assert fnames, "No files provided to calculate the median size."
    return sorted(fnames, key=lambda f: os.stat(f).st_size)[(len(fnames) - 1) // 2]

def average_depth(rc_table, read_length):
    mean_depths = read_length * rc_table.mapped / rc_table.length
    return weighted_median(mean_depths, rc_table.length)

def shared_chroms(*tables):
    chroms = tables[0].chromosome.drop_duplicates()
    for tab in tables[1:]:
        if tab is not None:
            new_chroms = tab.chromosome.drop_duplicates()
            chroms = chroms[chroms.isin(new_chroms)]
    return [None if tab is None else tab[tab.chromosome.isin(chroms)] for tab in tables]

def absolute_dataframe(cnarr, ploidy, purity, is_haploid_x_reference, diploid_parx_genome, is_sample_female):
    df = get_as_dframe_and_set_reference_and_expect_copies(
        cnarr, ploidy, is_haploid_x_reference, diploid_parx_genome, is_sample_female
    )
    df["absolute"] = df.apply(
        lambda row: _log2_ratio_to_absolute(
            row["log2"], row["reference"], row["expect"], purity
        ),
        axis=1,
    )
    return df[["absolute", "expect", "reference"]]

def log2_ratios(
    cnarr, absolutes, ploidy, is_haploid_x_reference, diploid_parx_genome, min_abs_val=1e-3, round_to_int=False
):
    # Round absolute copy numbers to integer values
    if round_to_int:
        absolutes = absolutes.round()
    # Avoid a logarithm domain error
    ratios = np.log2(np.maximum(absolutes / ploidy, min_abs_val))
    # Adjust sex chromosomes to be relative to the reference
    if is_haploid_x_reference:
        ratios[(cnarr.chr_x_filter(diploid_parx_genome)).values] += 1.0
    ratios[(cnarr.chr_y_filter(diploid_parx_genome)).values] += 1.0
    return ratios

def absolute_threshold(cnarr, ploidy, thresholds, is_haploid_x_reference):
    absolutes = np.zeros(len(cnarr), dtype=np.float64)
    for idx, row in enumerate(cnarr):
        ref_copies = _reference_copies_pure(row.chromosome, ploidy, is_haploid_x_reference)
        if np.isnan(row.log2):
            # XXX fallback
            logging.warning(
                "log2=nan found; replacing with neutral copy number %s", ref_copies
            )
            absolutes[idx] = ref_copies
            continue
        cnum = 0
        for cnum, thresh in enumerate(thresholds):
            if row.log2 <= thresh:
                if ref_copies != ploidy:
                    cnum = int(cnum * ref_copies / ploidy)
                break
        else:
            cnum = int(np.ceil(_log2_ratio_to_absolute_pure(row.log2, ref_copies)))
        absolutes[idx] = cnum
    return absolutes

def absolute_clonal(cnarr, ploidy, purity, is_haploid_x_reference, diploid_parx_genome, is_sample_female):
    df = absolute_dataframe(cnarr, ploidy, purity, is_haploid_x_reference, diploid_parx_genome, is_sample_female)

    return df["absolute"]

def absolute_pure(cnarr, ploidy, is_haploid_x_reference):
    absolutes = np.zeros(len(cnarr), dtype=np.float64)
    for i, row in enumerate(cnarr):
        ref_copies = _reference_copies_pure(row.chromosome, ploidy, is_haploid_x_reference)
        absolutes[i] = _log2_ratio_to_absolute_pure(row.log2, ref_copies)
    return absolutes

def _reference_copies_pure(chrom, ploidy, is_haploid_x_reference):
    chrom = chrom.lower()
    if chrom in ["chry", "y"] or (is_haploid_x_reference and chrom in ["chrx", "x"]):
        ref_copies = ploidy // 2
    else:
        ref_copies = ploidy
    return ref_copies

def _log2_ratio_to_absolute(log2_ratio, ref_copies, expect_copies, purity=None):
    if purity and purity < 1.0:
        ncopies = (ref_copies * 2**log2_ratio - expect_copies * (1 - purity)) / purity
    else:
        ncopies = _log2_ratio_to_absolute_pure(log2_ratio, ref_copies)
    return ncopies

def _log2_ratio_to_absolute_pure(log2_ratio, ref_copies):
    ncopies = ref_copies * 2**log2_ratio
    return ncopies

def do_sex(cnarrs, is_haploid_x_reference, diploid_parx_genome):
    def strsign(num):
        if num > 0:
            return "+%.3g" % num
        return "%.3g" % num

    def guess_and_format(cna):
        is_xy, stats = cna.compare_sex_chromosomes(is_haploid_x_reference, diploid_parx_genome)
        return (
            cna.meta["filename"] or cna.sample_id,
            "Male" if is_xy else "Female",
            strsign(stats["chrx_ratio"]) if stats else "NA",
            strsign(stats["chry_ratio"]) if stats else "NA",
        )

    rows = (guess_and_format(cna) for cna in cnarrs)
    columns = ["sample", "sex", "X_logratio", "Y_logratio"]
    return pd.DataFrame.from_records(rows, columns=columns)

def do_metrics(cnarrs, segments=None, skip_low=False):
    # Catch if passed args are single CopyNumArrays instead of lists
    from .cnary import CopyNumArray as CNA

    if isinstance(cnarrs, CNA):
        cnarrs = [cnarrs]
    if isinstance(segments, CNA):
        segments = [segments]
    elif segments is None:
        segments = [None]
    else:
        segments = list(segments)
    if skip_low:
        cnarrs = (cna.drop_low_coverage() for cna in cnarrs)
    rows = (
        (cna.meta.get("filename", cna.sample_id), len(seg) if seg is not None else "-")
        + ests_of_scale(cna.residuals(seg).values)
        for cna, seg in zip_repeater(cnarrs, segments)
    )
    colnames = ["sample", "segments", "stdev", "mad", "iqr", "bivar"]
    return pd.DataFrame.from_records(rows, columns=colnames)

def zip_repeater(iterable, repeatable):
    rpt_len = len(repeatable)
    if rpt_len == 1:
        rpt = repeatable[0]
        for it in iterable:
            yield it, rpt
    else:
        i = -1
        for i, (it, rpt) in enumerate(zip(iterable, repeatable)):
            yield it, rpt
        # Require lengths to match
        if i + 1 != rpt_len:
            raise ValueError(
                "Number of unsegmented and segmented input files did not match "
                + f"({i} vs. {rpt_len})"
            )

def ests_of_scale(deviations):
    std = np.std(deviations, dtype=np.float64)
    mad = descriptives.median_absolute_deviation(deviations)
    iqr = descriptives.interquartile_range(deviations)
    biw = descriptives.biweight_midvariance(deviations)
    return (std, mad, iqr, biw)

def make_pi_func(alpha):
    # ENH: weighted percentile
    pct_lo = 100 * alpha / 2
    pct_hi = 100 * (1 - alpha / 2)
    def pi_func(ser, _w):
        return np.percentile(ser, [pct_lo, pct_hi])
    return pi_func

def calc_intervals(bins_log2s, weights, func):
    out_vals_lo = np.repeat(np.nan, len(bins_log2s))
    out_vals_hi = np.repeat(np.nan, len(bins_log2s))
    for i, ser in enumerate(bins_log2s):
        if len(ser):
            wt = weights[ser.index]
            assert (wt.index == ser.index).all()
            out_vals_lo[i], out_vals_hi[i] = func(ser.values, wt.values)
    return out_vals_lo, out_vals_hi

def _bca_correct_alpha(values, weights, bootstrap_dist, alphas):
    n_boots = len(bootstrap_dist)
    orig_mean = np.average(values, weights=weights)
    logging.warning(
        "boot samples less: %s / %s", (bootstrap_dist < orig_mean).sum(), n_boots
    )
    n_boots_below = (bootstrap_dist < orig_mean).sum()
    if n_boots_below == 0:
        logging.warning("boots mean %s, orig mean %s", bootstrap_dist.mean(), orig_mean)
    else:
        logging.warning("boot samples less: %s / %s", n_boots_below, n_boots)
    z0 = stats.norm.ppf((bootstrap_dist < orig_mean).sum() / n_boots)
    zalpha = stats.norm.ppf(alphas)
    # Jackknife influence values
    u = np.array(
        [
            np.average(
                np.concatenate([values[:i], values[i + 1 :]]),
                weights=np.concatenate([weights[:i], weights[i + 1 :]]),
            )
            for i in range(len(values))
        ]
    )
    uu = u.mean() - u
    acc = (u**3).sum() / (6 * (uu**2).sum() ** 1.5)
    alphas = stats.norm.cdf(z0 + (z0 + zalpha) / (1 - acc * (z0 + zalpha)))
    logging.warning(
        "New alphas: %s -- via z0=%s, za=%s, acc=%s", alphas, z0, zalpha, acc
    )
    if not 0 < alphas[0] < 1 and 0 < alphas[1] < 1:
        raise ValueError(f"CI alphas should be in (0,1); got {alphas}")
    return alphas

def segment_mean(cnarr, skip_low=False):
    if skip_low:
        cnarr = cnarr.drop_low_coverage()
    if len(cnarr) == 0:
        return np.nan
    if "weight" in cnarr and cnarr["weight"].any():
        return np.average(cnarr["log2"], weights=cnarr["weight"])
    return cnarr["log2"].mean()

def merge_samples(filenames):
    def label_with_gene(cnarr):
        row2label = lambda row: f"{row.chromosome}:{row.start}-{row.end}:{row.gene}"
        return cnarr.data.apply(row2label, axis=1)
    if not filenames:
        return []
    first_cnarr = read_cna(filenames[0])
    out_table = first_cnarr.data.reindex(columns=["chromosome", "start", "end", "gene"])
    out_table["label"] = label_with_gene(first_cnarr)
    out_table[first_cnarr.sample_id] = first_cnarr["log2"]
    for fname in filenames[1:]:
        cnarr = read_cna(fname)
        if not (
            len(cnarr) == len(out_table)
            and (label_with_gene(cnarr) == out_table["label"]).all()
        ):
            raise ValueError(f"Mismatched row coordinates in {fname}")
        # Copy the next column by sample ID
        if cnarr.sample_id in out_table.columns:
            raise ValueError(f"Duplicate sample ID: {cnarr.sample_id}")
        out_table[cnarr.sample_id] = cnarr["log2"]
        del cnarr
    return out_table

def fmt_jtv(sample_ids, table):
    outheader = ["CloneID", "Name"] + sample_ids
    outtable = pd.concat(
        [
            pd.DataFrame(
                {
                    "CloneID": "IMAGE:",
                    "Name": table["label"],
                }
            ),
            table.drop(["chromosome", "start", "end", "gene", "label"], axis=1),
        ],
        axis=1,
    )
    outrows = outtable.itertuples(index=False)
    return outheader, outrows

def export_nexus_basic(cnarr):
    out_table = cnarr.data.reindex(
        columns=["chromosome", "start", "end", "gene", "log2"]
    )
    out_table["probe"] = cnarr.labels()
    return out_table

def export_nexus_ogt(cnarr, varr, min_weight=0.0):
    if min_weight and "weight" in cnarr:
        mask_low_weight = cnarr["weight"] < min_weight
        logging.info(
            "Dropping %d bins with weight below %f", mask_low_weight.sum(), min_weight
        )
        cnarr.data = cnarr.data[~mask_low_weight]
    bafs = varr.baf_by_ranges(cnarr)
    logging.info("Placed %d variants into %d bins", sum(~np.isnan(bafs)), len(cnarr))
    out_table = cnarr.data.reindex(columns=["chromosome", "start", "end", "log2"])
    out_table = out_table.rename(
        columns={
            "chromosome": "Chromosome",
            "start": "Position",
            "end": "Position",
            "log2": "Log R Ratio",
        }
    )
    out_table["B-Allele Frequency"] = bafs
    return out_table

def assign_ci_start_end(segarr, cnarr):
    lefts_rights = (
        (bins.end.iat[0], bins.start.iat[-1])
        if len(bins.end) > 0 and len(bins.start) > 0
        else (np.nan, np.nan)
        for _seg, bins in cnarr.by_ranges(segarr, mode="outer")
    )
    ci_lefts, ci_rights = zip(*lefts_rights)
    return segarr.as_dataframe(segarr.data.assign(ci_left=ci_lefts, ci_right=ci_rights))

def export_gistic_markers(cnr_fnames):
    colnames = ["ID", "CHROM", "POS"]
    out_chunks = []
    # TODO since markers will mostly be the same,
    #   detect duplicates & exclude them
    # seen_marker_ids = None
    for fname in cnr_fnames:
        cna = read_cna(fname)
        marker_ids = cna.labels()
        tbl = pd.concat(
            [
                pd.DataFrame(
                    {
                        "ID": marker_ids,
                        "CHROM": cna.chromosome,
                        "POS": cna.start + 1,
                    },
                    columns=colnames,
                ),
                pd.DataFrame(
                    {
                        "ID": marker_ids,
                        "CHROM": cna.chromosome,
                        "POS": cna.end,
                    },
                    columns=colnames,
                ),
            ],
            ignore_index=True,
        )
        out_chunks.append(tbl)
    return pd.concat(out_chunks).drop_duplicates()

def ref_means_nbins(tumor_segs, normal_cn):
    if normal_cn:
        log2s_in_segs = [bins["log2"] for _seg, bins in normal_cn.by_ranges(tumor_segs)]
        # For the normal/reference bin count, take the mean of the bin values
        # within each segment so that segments match between tumor and normal.
        # ENH: weighted mean, like genemetrics
        ref_means = np.array([s.mean() for s in log2s_in_segs])
        if "probes" in tumor_segs:
            nbins = tumor_segs["probes"]
        else:
            nbins = np.array([len(s) for s in log2s_in_segs])
    else:
        # Assume neutral reference log2 across all segments
        # (weights already account for reference log2)
        ref_means = np.zeros(len(tumor_segs))
        if "weight" in tumor_segs and (tumor_segs["weight"] > 1.0).any():
            # Segment weights are already multiplied by probe counts
            nbins = tumor_segs["weight"]
            # Rescale to average 1.0 (we'll do the same below, too)
            nbins /= nbins.max() / nbins.mean()
        else:
            if "probes" in tumor_segs:
                nbins = tumor_segs["probes"]
            else:
                logging.warning(
                    "No probe counts in tumor segments file and no "
                    "normal reference given; guessing normal "
                    "read-counts-per-segment from segment sizes"
                )
                sizes = tumor_segs.end - tumor_segs.start
                nbins = sizes / sizes.mean()
            if "weight" in tumor_segs:
                # Already checked -- these are old-style weights that were not
                # multiplied by `probes` originally
                nbins *= tumor_segs["weight"] / tumor_segs["weight"].mean()
    return ref_means, nbins

def merge_gaps(regions, min_gap):
    prev = next(regions)
    for reg in regions:
        if reg.start - prev.end < min_gap:
            # Merge
            prev = prev._replace(end=reg.end)
        else:
            # Done merging; move on
            yield prev
            prev = reg
    # Residual
    yield prev

def drop_small(regions, min_length):
    return (reg for reg in regions
            if reg.end - reg.start >= min_length)

def _get_chr_pos_from_array(chr_pos_array):
    chr_pos = {}
    for i, sn in enumerate(chr_pos_array):
        chr_name = f"chr{int(sn)}"
        if chr_name not in chr_pos:
            chr_pos[chr_name] = i
    return chr_pos

def read_scevan(
    adata: AnnData,
    scevan_res_dir: str | Path,
    scevan_res_table: str | Path | None = None,
    *,
    subclones: bool = True,
    inplace: bool = True,
    subset: bool = True,
    key_added: str = "scevan",
) -> AnnData | None:
    scevan_res_dir = Path(scevan_res_dir)
    scevan_res_file = list(scevan_res_dir.glob("*_CNAmtx.RData"))
    scevan_subclones_file = list(scevan_res_dir.glob("*_CNAmtxSubclones.RData"))
    scevan_anno_file = list(scevan_res_dir.glob("*_count_mtx_annot.RData"))

    if len(scevan_res_file) != 1 or len(scevan_subclones_file) > 1 or len(scevan_anno_file) != 1:
        raise ValueError(
            "There must be exactely one CNA_mtx and count_mtx_annot file and at most one "
            "CNAmtxSubclones file in the result directory!"
        )

    # read data
    if scevan_res_table is not None:
        tumor_normal_call = pd.read_csv(scevan_res_table, index_col=0)
    else:
        tumor_normal_call = None
        logging.warning("No `scevan_res_table` specified. Will not add tumor/normal classification.")
    scevan_res = pyreadr.read_r(scevan_res_file[0])["CNA_mtx_relat"].T
    scevan_anno = pyreadr.read_r(scevan_anno_file[0])["count_mtx_annot"]
    scevan_subclone_res = None
    if subclones and len(scevan_subclones_file):
        scevan_subclone_res = pyreadr.read_r(scevan_subclones_file[0])["results.com"].T

    if not inplace:
        adata = adata.copy()

    # add obs annotation
    if tumor_normal_call is not None:
        adata.obs[f"{key_added}_class"] = tumor_normal_call["class"]
        adata.obs[f"{key_added}_confident_normal"] = tumor_normal_call["confidentNormal"]
        if "subclone" in tumor_normal_call.columns:
            adata.obs[f"{key_added}_subclone"] = tumor_normal_call["subclone"].apply(
                lambda x: f"{int(x)}" if not pd.isnull(x) else np.nan
            )

    if subset:
        adata._inplace_subset_obs(scevan_res.index.values)

    adata.obsm[f"X_{key_added}"] = scevan_res.reindex(adata.obs_names).values
    if scevan_subclone_res is not None:
        adata.obsm[f"X_{key_added}"].loc[scevan_subclone_res.index, :] = scevan_subclone_res
    adata.uns[key_added] = {"chr_pos": _get_chr_pos_from_array(scevan_anno["seqnames"])}

    if not inplace:
        return adata

def neighbors(
    adata: AnnData,
    use_rep: str = "cnv_pca",
    key_added: str = "cnv_neighbors",
    inplace: bool = True,
    **kwargs,
):
    if f"X_{use_rep}" not in adata.obsm and use_rep == "cnv_pca":
        logging.warning("X_cnv_pca not found in adata.obsm. Computing PCA with default parameters")  # type: ignore
        tl.pca(adata)

    return sc.pp.neighbors(adata, use_rep=f"X_{use_rep}", key_added=key_added, copy=not inplace, **kwargs)

def _natural_sort(l: Sequence):
    def convert(text):
        return int(text) if text.isdigit() else text.lower()
    def alphanum_key(key):
        return [convert(c) for c in re.split("([0-9]+)", key)]
    return sorted(l, key=alphanum_key)

def _calculate_gene_averages(
    convolved_gene_names: np.ndarray,
    smoothed_x: np.ndarray,
) -> pd.DataFrame:

    ## create a dictionary to store the gene values per sample
    gene_to_values = {}
    # Calculate the number of genes in each convolution, will be same as the window size default=100
    length = len(convolved_gene_names[0])
    # Convert the flattened convolved gene names to a list
    flatten_list = list(convolved_gene_names.flatten())
    # For each sample in smoothed_x find the value for each gene and store it in a dictionary
    for sample, row in enumerate(smoothed_x):
        # Create sample level in the dictionary
        if sample not in gene_to_values:
            gene_to_values[sample] = {}
        # For each gene in the flattened gene list find the value and store it in the dictionary
        for i, gene in enumerate(flatten_list):
            if gene not in gene_to_values[sample]:
                gene_to_values[sample][gene] = []
            # As the gene list has been flattend we can use the floor division of the index
            # to get the correct position of the gene to get the value and store it in the dictionary
            gene_to_values[sample][gene].append(row[i // length])
    for sample in gene_to_values:
        for gene in gene_to_values[sample]:
            gene_to_values[sample][gene] = np.mean(gene_to_values[sample][gene])
    convolved_gene_values = pd.DataFrame(gene_to_values).T
    return convolved_gene_values

def _running_mean_by_chromosome(
    expr, var, window_size, step, calculate_gene_values
) -> tuple[dict, np.ndarray, pd.DataFrame | None]:
    chromosomes = _natural_sort([x for x in var["chromosome"].unique() if x.startswith("chr") and x != "chrM"])
    running_means = [
        _running_mean_for_chromosome(chr, expr, var, window_size, step, calculate_gene_values) for chr in chromosomes
    ]
    running_means, convolved_dfs = zip(*running_means, strict=False)
    chr_start_pos = {}
    for chr, i in zip(chromosomes, np.cumsum([0] + [x.shape[1] for x in running_means]), strict=False):
        chr_start_pos[chr] = i
    ## Concatenate the gene dfs
    if calculate_gene_values:
        convolved_dfs = pd.concat(convolved_dfs, axis=1)
    return chr_start_pos, np.hstack(running_means), convolved_dfs

def _get_reference(
    adata: AnnData,
    reference_key: str | None,
    reference_cat: None | str | Sequence[str],
    reference: np.ndarray | None,
) -> np.ndarray:
    if reference is None:
        if reference_key is None or reference_cat is None:
            logging.warning(
                "Using mean of all cells as reference. For better results, "
                "provide either `reference`, or both `reference_key` and `reference_cat`. "
            )  # type: ignore
            reference = np.mean(adata.X, axis=0)
        else:
            obs_col = adata.obs[reference_key]
            if isinstance(reference_cat, str):
                reference_cat = [reference_cat]
            reference_cat = np.array(reference_cat)
            reference_cat_in_obs = np.isin(reference_cat, obs_col)
            if not np.all(reference_cat_in_obs):
                raise ValueError(
                    "The following reference categories were not found in "
                    "adata.obs[reference_key]: "
                    f"{reference_cat[~reference_cat_in_obs]}"
                )
            reference = np.vstack([np.mean(adata.X[obs_col.values == cat, :], axis=0) for cat in reference_cat])
    if reference.ndim == 1:
        reference = reference[np.newaxis, :]
    if reference.shape[1] != adata.shape[1]:
        raise ValueError("Reference must match the number of genes in AnnData. ")
    return reference

def cnv_score(
    adata: AnnData,
    groupby: str = "cnv_leiden",
    *,
    use_rep: str = "cnv",
    key_added: str = "cnv_score",
    inplace: bool = True,
    obs_key=None,
) -> Mapping[Any, np.number] | None:

    if obs_key is not None:
        warnings.warn(
            "The obs_key argument has been renamed to `groupby` for consistency with "
            "other functions and will be removed in the future. ",
            category=FutureWarning,
            stacklevel=2,
        )
        groupby = obs_key

    if groupby not in adata.obs.columns and groupby == "cnv_leiden":
        raise ValueError("`cnv_leiden` not found in `adata.obs`. Did you run `tl.leiden`?")
    cluster_score = {
        cluster: np.mean(np.abs(adata.obsm[f"X_{use_rep}"][adata.obs[groupby].values == cluster, :]))
        for cluster in adata.obs[groupby].unique()
    }

    if inplace:
        score_array = np.array([cluster_score[c] for c in adata.obs[groupby]])
        adata.obs[key_added] = score_array
    else:
        return cluster_score

def ithgex(
    adata: AnnData,
    groupby: str,
    *,
    use_raw: bool | None = None,
    layer: str | None = None,
    inplace: bool = True,
    key_added: str = "ithgex",
) -> Mapping[str, float] | None:

    groups = adata.obs[groupby].unique()
    ithgex = {}
    for group in groups:
        tmp_adata = adata[adata.obs[groupby] == group, :]
        X = _choose_mtx_rep(tmp_adata, use_raw, layer)
        if sp.issparse(X):
            X = X.todense()
        if X.shape[0] <= 1:
            continue
        pcorr = np.corrcoef(X, rowvar=True)
        assert pcorr.shape == (
            tmp_adata.shape[0],
            tmp_adata.shape[0],
        ), f"pcorr is a cell x cell matrix {tmp_adata.shape[0]} {pcorr.shape}"
        q75, q25 = np.percentile(pcorr, [75, 25])
        ithgex[group] = q75 - q25

    if inplace:
        ithgex_obs = np.empty(adata.shape[0])
        for group in groups:
            ithgex_obs[adata.obs[groupby] == group] = ithgex[group]
        adata.obs[key_added] = ithgex_obs
    else:
        return ithgex

def ithcna(
    adata: AnnData,
    groupby: str,
    *,
    use_rep: str = "X_cnv",
    key_added: str = "ithcna",
    inplace: bool = True,
) -> Mapping[str, float] | None:

    groups = adata.obs[groupby].unique()
    ithcna = {}
    for group in groups:
        tmp_adata = adata[adata.obs[groupby] == group, :]
        X = tmp_adata.obsm[use_rep]
        if sp.issparse(X):
            X = X.todense()
        if X.shape[0] <= 1:
            continue
        pcorr = np.corrcoef(X, rowvar=True)
        assert pcorr.shape == (
            tmp_adata.shape[0],
            tmp_adata.shape[0],
        ), "pcorr is a cell x cell matrix"
        q75, q25 = np.percentile(pcorr, [75, 25])
        ithcna[group] = q75 - q25

    if inplace:
        ithcna_obs = np.empty(adata.shape[0])
        for group in groups:
            ithcna_obs[adata.obs[groupby] == group] = ithcna[group]
        adata.obs[key_added] = ithcna_obs
    else:
        return ithcna

def umap(
    adata: AnnData,
    neighbors_key: str = "cnv_neighbors",
    key_added: str = "cnv_umap",
    inplace: bool = True,
    **kwargs,
):
    tmp_adata = sc.tl.umap(adata, neighbors_key=neighbors_key, copy=True, **kwargs)

    if inplace:
        adata.obsm[f"X_{key_added}"] = tmp_adata.obsm["X_umap"]
    else:
        return tmp_adata.obsm["X_umap"]

def tsne(
    adata: AnnData,
    use_rep: str = "cnv_pca",
    key_added: str = "cnv_tsne",
    inplace: bool = True,
    **kwargs,
):

    if f"X_{use_rep}" not in adata.obsm and use_rep == "cnv_pca":
        logging.warning("X_cnv_pca not found in adata.obsm. Computing PCA with default parameters")  # type: ignore
        pca(adata)
    tmp_adata = sc.tl.tsne(adata, use_rep="X_cnv_pca", copy=True, **kwargs)

    if inplace:
        adata.obsm[f"X_{key_added}"] = tmp_adata.obsm["X_tsne"]
    else:
        return tmp_adata.obsm["X_tsne"]

def tsne(adata, **kwargs):
    """Plot the CNV t-SNE.

    Thin wrapper around :func:`scanpy.pl.embedding`.
    """
    return sc.pl.embedding(adata, "cnv_tsne", **kwargs)

def oligodendroglioma() -> AnnData:
    with pkg_resources.path(data, "oligodendroglioma.h5ad") as p:
        return sc.read_h5ad(p)

def __init__(self, reference_genome, biotypes=["protein_coding"]):

        if 'ensembl_api_region' in reference_genome:
            self.url_template = reference_genome["ensembl_api_region"]
        else:
            _logger.error("ensembl_api_region tag is missing for %s reference genome" % (self.reference_genome["name"]))
            self.url_template = None
        self.biotypes = biotypes

def get_info(self, region):
       regs = decode_region(region)
        if len(regs) == 0:
            _logger.debug("get_info called without region")
            return None
        (c, (start, end)) = regs[0]
        response = requests.get(self.url_template.format(region=region))
        ret = []
        if "error" in response.json():
            return "No information"
        for i in response.json():
            if ("biotype" in i) and i["biotype"] in self.biotypes:
                if i["start"] > start and i["end"] < end:
                    position = "inside"
                elif i["start"] < start and i["end"] > end:
                    position = "cover"
                elif i["start"] < start:
                    position = "intersect left"
                else:
                    position = "intersect right"
                if "external_name" in i:
                    ret.append("%s (%s %s)" % (i["external_name"], i["id"], position))
                else:
                    ret.append("%s (%s %s)" % (i["id"], i["id"], position))
        return ", ".join(ret)

def __init__(self, filename, max_fragment_len=5000, max_read_len=300, reference_filename=False, init_log=True):
        self.max_read_len = max_read_len
        self.max_frg_len = max_fragment_len
        self.reference_genome = None
        self.filename = filename
        self.reference_filename = reference_filename
        if filename[-4:] == ".bam":
            self.file = pysam.AlignmentFile(filename, "rb")
        elif filename[-4:] == ".sam":
            self.file = pysam.AlignmentFile(filename, "r")
        elif filename[-5:] == ".cram":
            if reference_filename:
                self.file = pysam.AlignmentFile(filename, "rc", reference_filename=reference_filename)
            else:
                self.file = pysam.AlignmentFile(filename, "rc")
        else:
            _logger.warning("Unsuported file type: " + filename)
        self.len = {}
        if self.file:
            if init_log:
                _logger.info("File: " + filename + " successfully open")
            self.reference_genome = Genome.detect_genome(self.file.header.references, self.file.header.lengths)
            if self.reference_genome:
                if init_log:
                    _logger.info("Detected reference genome: " + self.reference_genome)
            for c, l in zip(self.file.header.references, self.file.header.lengths):
                self.len[c] = l

def read_chromosome(self, chr_name):
        if not (chr_name in self.len):
            _logger.warning("Can not find chromosome '%s' in file '%s'." % (chr_name, self.filename))
            return None, None, None
        _logger.debug("Reading chromosome %s from filename %s" % (chr_name, self.filename))
        n = self.len[chr_name] // 100 + 1
        rd_p = np.zeros(n)
        rd_u = np.zeros(n)
        his_read_frg = np.zeros((self.max_read_len, self.max_frg_len))
        try:
            for r in self.file.fetch(chr_name, multiple_iterators=True):
                assert isinstance(r, pysam.libcalignedsegment.AlignedSegment)
                if r.template_length and r.reference_length:
                    fl = abs(r.template_length)
                    rl = r.reference_length
                    if (rl < self.max_read_len) and (fl < self.max_frg_len):
                        his_read_frg[rl][fl] += 1
                    if r.is_unmapped or r.is_secondary or r.is_duplicate:
                        continue
                if r.reference_start and r.reference_end and not (r.mapping_quality is None):
                    mid = (r.reference_end + r.reference_start) // 200
                    if mid >= 0 and mid < n:
                        rd_p[mid] += 1
                        if r.mapping_quality > 0:
                            rd_u[mid] += 1
                    else:
                        _logger.warning("Record: " + r.to_string())
                        _logger.warning("Out of bound! Ignoring...")

        except IOError:
            _logger.error("Error while reading file '%s'" % self.filename)
            exit(0)
        except ValueError:
            _logger.error("Error while reading file '%s'. Probably index is missing." % self.filename)
            exit(0)
        return rd_p, rd_u, his_read_frg

def pileup(self, chr_name, pos, ref, alt, tmp_file=".cnvpytor"):

        if not (chr_name in self.len):
            _logger.warning("Can not find chromosome '%s' in file '%s'." % (chr_name, self.filename))
            return
        _logger.debug("Pileup chromosome %s from filename %s" % (chr_name, self.filename))
        tmp_file += "_" + str(random.randint(0, 10000000000)) + "_" + chr_name
        f = open(tmp_file, "w")
        for i in pos:
            print(chr_name, i, file=f)
        f.close()
        if self.reference_filename:
            mpile = pysam.mpileup("-r", chr_name, "-l", tmp_file, "--reference", self.reference_filename, self.filename)
        else:
            mpile = pysam.mpileup("-r", chr_name, "-l", tmp_file, self.filename)
        os.remove(tmp_file)
        pos_seq = dict([(int(x.split("\t")[1]), x.split("\t")[4].upper()) for x in mpile.split("\n") if x != ""])
        nref = [0] * len(pos)
        nalt = [0] * len(pos)
        for ix in range(len(pos)):
            if pos[ix] in pos_seq:
                nref[ix] = pos_seq[pos[ix]].count(ref[ix]) + pos_seq[pos[ix]].count(".") + pos_seq[pos[ix]].count(",")
                nalt[ix] = pos_seq[pos[ix]].count(alt[ix])
        return nref, nalt

def get_cnvpytor_signal(self, md5, chrom, bin_size, signal, flag):
        signal_details = md5.get_signal(chrom, bin_size, signal, flag)
        return signal_details

def create_wig_offset_transform(self, md5, chr_list, bin_size, signal, flag, offset):
        self.add_header_list(chr_list)

        for (chrom, length) in chr_list:
            signal_details = md5.get_signal(chrom, bin_size, signal, flag)
            if isinstance(signal_details, np.ndarray):
                signal_value_list = signal_details[()]
                signal_value_list[signal_value_list != 0] += offset

                signal_value_list = np.absolute(signal_value_list)
                self.add_fixedstep(chrom, 0, signal_value_list, span=bin_size, step=bin_size)

def create_wig(self, md5, chr_list, bin_size, signal, flag):
        self.add_header_list(chr_list)
        for (chrom, length) in chr_list:
            signal_details = md5.get_signal(chrom, bin_size, signal, flag)
            if isinstance(signal_details, np.ndarray):
                signal_value_list = signal_details[()]
                self.add_fixedstep(chrom, 0, signal_value_list, span=bin_size, step=bin_size)

def pytor_names(self):
        name_list = []
        for filename in self.files:
            name_list.append(Path(filename).resolve().stem)
        return name_list

def export_directory(self):

        if self.dir.is_dir():
            if len(self.files) > 1:
                # for multiple input file
                default_name = self.dir.joinpath("cnvpytor_jbrowse_export")

            else:
                # for single_input_file
                default_name = self.dir.joinpath("jbrowse_{}".format(self.pytor_names[0]))

            if default_name.exists():
                tmp_name = default_name
                i = 1
                while default_name.exists():
                    update_name = "{}({})".format(tmp_name.name, i)
                    default_name = default_name.with_name(update_name)
                    i = i+1
            return default_name
        else:
            if self.dir.parent.exists():
                return self.dir
            else:
                _logger.error("Error: incorrect export path: {}".format(self.dir))
                exit(0)

def export_tracklist_file(self):
        track_list = self.export_dir.joinpath("trackList.json")
        return track_list

def export_ref_file(self):
        ref_file = self.export_seq_dir.joinpath("refSeqs.json")
        return ref_file

def signal_name(self, bin_size, signal, flags=0):
        if signal in self.signal_dct:
            try:
                return self.signal_dct[signal] % {"bin_size": bin_size, "rd_flag": Signals().suffix_rd_flag(flags),
                                                  "snp_flag": Signals().suffix_snp_flag(flags),
                                                  "flag": Signals().suffix_flag(flags)}
            except TypeError:
                return None
        else:
            return None

def rd_chr_bin(self, root_io):
        chr_bs = root_io.chromosomes_bin_sizes_with_signal("RD")
        chrs = {}
        bss = []
        for c, b in chr_bs:
            if c not in chrs:
                chrs[c] = []
            chrs[c].append(int(b))
            if int(b) not in bss:
                bss.append(int(b))
        return chrs, bss

def snp_chr_bin(self, root_io):
        chr_bs = root_io.chromosomes_bin_sizes_with_signal("SNP likelihood", FLAG_USEMASK)
        chrs = {}
        bss = []
        for c, b in chr_bs:
            if c not in chrs:
                chrs[c] = []
            chrs[c].append(int(b))
            if int(b) not in bss:
                bss.append(int(b))
        return chrs, bss

def create_bigwig(root_io, bigwig_file, chr_list, bin_size, signal_name, flag, offset=None):
       wig = None
       for (chrom, length) in chr_list:
           signal_details = root_io.get_signal(chrom, bin_size, signal_name, flag)
           if isinstance(signal_details, np.ndarray):
               signal_value_list = signal_details[()]
               if offset is not None:
                   signal_value_list[signal_value_list != 0] += offset
                   signal_value_list = np.absolute(signal_value_list)

               if not isinstance(wig, Wiggle):
                   wig = Wiggle(bigwig_file)
                   wig.add_header_list(chr_list)

               wig.add_fixedstep(chrom, 0, signal_value_list, span=bin_size, step=bin_size)

def rd_signal(self):
         _logger.debug("Create Read depth related signals")
        for root_index, root_io in enumerate(self.io):
            _logger.info("JBrowse export: RD related data for {}".format(self.pytor_names[root_index]))
            rd_chr, rd_bin = self.rd_chr_bin(root_io)
            chr_len = root_io.get_signal(None, None, "chromosome lengths")
            chr_list = list(zip(chr_len[::2].astype(str), chr_len[1::2].astype(int)))

            for signal_name, signal_dct in self.rd_signal_dct.items():
                _logger.info("JBrowse export: RD signal {}".format(signal_name))
                for index, flag in enumerate(signal_dct['FLAG']):
                    for bin_size in rd_bin:
                        signal = self.signal_name(bin_size, signal_name, flag)
                        bigwig_filename = "{}.bw".format(signal)
                        bigwig_file = self.export_data_dir_list[root_index].joinpath(bigwig_filename)
                        bigwig_file = str(bigwig_file)

                        self.create_bigwig(root_io, bigwig_file, chr_list, bin_size, signal_name, flag)

def snp_signal(self):
         _logger.debug("Create SNP related signals")
       for root_index, root_io in enumerate(self.io):
           _logger.info("JBrowse export: SNP related data for {}".format(self.pytor_names[root_index]))
           snp_chr, snp_bin = self.snp_chr_bin(root_io)

           chr_len = root_io.get_signal(None, None, "chromosome lengths")
           chr_list = list(zip(chr_len[::2].astype(str), chr_len[1::2].astype(int)))

           for signal_name, signal_dct in self.snp_signal_dct.items():
               _logger.info("JBrowse export: SNP signal {}".format(signal_name))
               for index, flag in enumerate(signal_dct['FLAG']):
                   if "offset" in signal_dct:
                       offset = signal_dct['offset'][index]
                       for bin_size in snp_bin:
                           signal = self.signal_name(bin_size, signal_name, flag)
                           bigwig_filename = "{}_offset{}.bw".format(signal, offset)
                           bigwig_file = self.export_data_dir_list[root_index].joinpath(bigwig_filename)
                           bigwig_file = str(bigwig_file)

                           self.create_bigwig(root_io, bigwig_file, chr_list, bin_size, signal_name, flag,
                                              offset=offset)

                   else:
                       for bin_size in snp_bin:
                           signal = self.signal_name(bin_size, signal_name, flag)
                           bigwig_filename = "{}.bw".format(signal)
                           bigwig_file = self.export_data_dir_list[root_index].joinpath(bigwig_filename)
                           bigwig_file = str(bigwig_file)

                           self.create_bigwig(root_io, bigwig_file, chr_list, bin_size, signal_name, flag)

def add_rd_config_track(self):
        _logger.debug("Get RD config track")
        track_dct_list = []
        for root_index, root_io in enumerate(self.io):
            rd_chr, rd_bin = self.rd_chr_bin(root_io)
            url_template_dct = []
            for signal_name, signal_dct in self.rd_signal_dct.items():
                if 'FLAG' in signal_dct:
                    for index, flag in enumerate(signal_dct['FLAG']):
                        suffix_rd_flag = Signals.suffix_rd_flag(flag)
                        signal_id = "{}_{}{}".format(self.pytor_names[root_index], signal_name, suffix_rd_flag)
                        scales = {}
                        for bin_size in rd_bin:
                            signal = self.signal_name(bin_size, signal_name, flag)
                            bigwig_filename = "{}.bw".format(signal)
                            bigwig_file = self.export_data_dir_list[root_index].joinpath(bigwig_filename)
                            bigwig_current_path = Path(bigwig_file.parent.parent.name).joinpath(bigwig_file.parent.name, bigwig_file.name).as_posix()
                            if bigwig_file.exists():
                                scales[bin_size] = bigwig_current_path

                        if len(scales) > 0:
                            url_template_dct.append({
                                "storeClass": "MultiScaleBigWig/Store/SeqFeature/MultiScaleBigWig",
                                "scales": scales,
                                "name": signal_id,
                                "color": signal_dct['color'][index],

                            })
            if len(url_template_dct) > 0:

                track_dct = {
                    "category": self.pytor_names[root_index],
                    'autoscale': 'local',
                    "storeClass": "MultiBigWig/Store/SeqFeature/MultiBigWig",
                    "showTooltips": True,
                    "showLabels": True,
                    "clickTooltips": True,
                    "key": "RD",
                    "label": "RD {}".format(self.pytor_names[root_index]),
                    "type": "MultiBigWig/View/Track/MultiWiggle/MultiXYPlot",
                    'useStdDev': True,
                    'urlTemplates': url_template_dct

                }
                track_dct_list.append(track_dct)
        return track_dct_list

