        with open(self.export_ref_file, 'w') as f:
            json.dump(chr_dct_list, f, indent=2)

def __init__(self, filename):
        self.reference_genome = None
        self.filename = filename
        self.file = None
        try:
            self.file = pysam.FastaFile(filename)
        except IOError:
            _logger.error("Problem opening file '%s' " % filename)
            exit(0)
        except ValueError:
            _logger.error("Index for filename '%s' is missing!" % filename)
            exit(0)

        self.len = {}
        if self.file:
            _logger.info("File: " + filename + " successfully open")
            self.reference_genome = Genome.detect_genome(self.file.references, self.file.lengths)
            if self.reference_genome:
                _logger.info("Detected reference genome: " + self.reference_genome)
            for c, l in zip(self.file.references, self.file.lengths):
                self.len[c] = l

def canonical_chrom_name(name):
         cname = name.upper().replace("CHROMOSOME", "").replace("CHROM", "").replace("CHR", "")
        if cname == "MT":
            cname = "M"
        if cname.startswith('NC_'):
            try:
                chrom_num = int(float(cname[3:]))
                if chrom_num <= 22:
                    cname = str(chrom_num)
                elif chrom_num == 23:
                    cname = 'X'
                elif chrom_num == 24:
                    cname = 'Y'
                elif chrom_num == 12920:
                    cname = 'M'
            except ValueError:
                cname = cname
        return cname

def check_resources(cls):
        _logger.debug("Checking reference genome resource files.")
        for i in cls.reference_genomes:
            if "gc_file" in cls.reference_genomes[i] and not os.path.exists(cls.reference_genomes[i]["gc_file"]):
                return False
            if "mask_file" in cls.reference_genomes[i] and not os.path.exists(cls.reference_genomes[i]["mask_file"]):
                return False
        return True

def download_resources(cls):
        _logger.info("Updating reference genome resource files...")
        for i in cls.reference_genomes:
            if "gc_file" in cls.reference_genomes[i] and not os.path.exists(cls.reference_genomes[i]["gc_file"]):
                _logger.info("Detecting missing GC resource file for reference genome '%s'" % i)
                res = cls.reference_genomes[i]["gc_file"]
                fn = res.split("/")[-1]
                url = "https://github.com/abyzovlab/CNVpytor/raw/master/cnvpytor/data/" + fn
                if is_downloadable(url):
                    _logger.info("Downloading GC resource file: %s", fn)
                    try:
                        download(url, res)
                        _logger.info("File downloaded.")
                    except Exception as e:
                        _logger.error("Problem with downloading/saving resource files.")
                        _logger.error("Exception details: " + str(e))

                else:
                    _logger.warning("GC resource file is not downloadable!")
            if "mask_file" in cls.reference_genomes[i] and not os.path.exists(cls.reference_genomes[i]["mask_file"]):
                _logger.info("Detecting missing MASK resource file for reference genome '%s'" % i)
                res = cls.reference_genomes[i]["mask_file"]
                fn = res.split("/")[-1]
                url = "https://github.com/abyzovlab/CNVpytor/raw/master/cnvpytor/data/" + fn
                if is_downloadable(url):
                    _logger.info("Downloading MASK resource file: %s", fn)
                    try:
                        download(url, res)
                        _logger.info("File downloaded.")
                    except Exception as e:
                        _logger.error("Problem with downloading/saving resource files.")
                        _logger.error("Exception details: " + str(e))
        _logger.info("Done.")

def is_autosome(cls, name):
        if cls.detected_genome is None:
            return (not cls.is_sex_chrom(name)) and (not cls.is_mt_chrom(name)) and (not ("GL" in name.upper())) and (
                not ("NC" in name.upper()))
        if cls.extended_chrom_name(name) in cls.reference_genomes[cls.detected_genome]["chromosomes"]:
            return cls.reference_genomes[cls.detected_genome]["chromosomes"][cls.extended_chrom_name(name)][1] == "A"
        elif name in cls.reference_genomes[cls.detected_genome]["chromosomes"]:
            return cls.reference_genomes[cls.detected_genome]["chromosomes"][name][1] == "A"
        return False

def is_sex_chrom(cls, name):
        if cls.detected_genome is None:
            return cls.canonical_chrom_name(name) in {"X", "Y", "SEX"}
        if cls.extended_chrom_name(name) in cls.reference_genomes[cls.detected_genome]["chromosomes"]:
            return cls.reference_genomes[cls.detected_genome]["chromosomes"][cls.extended_chrom_name(name)][1] == "S"
        elif name in cls.reference_genomes[cls.detected_genome]["chromosomes"]:
            return cls.reference_genomes[cls.detected_genome]["chromosomes"][name][1] == "S"
        return False

def is_mt_chrom(cls, name):
        if cls.detected_genome is None:
            return cls.canonical_chrom_name(name) in {"M", "MT"}
        if cls.extended_chrom_name(name) in cls.reference_genomes[cls.detected_genome]["chromosomes"]:
            return cls.reference_genomes[cls.detected_genome]["chromosomes"][cls.extended_chrom_name(name)][1] == "M"
        elif name in cls.reference_genomes[cls.detected_genome]["chromosomes"]:
            return cls.reference_genomes[cls.detected_genome]["chromosomes"][name][1] == "M"

        return False

def detect_genome(cls, names, lengths):
        for g in cls.reference_genomes:
            found = True
            checked = False
            for c, l in zip(names, lengths):
                if ((c in cls.reference_genomes[g]["chromosomes"]) or (
                        cls.extended_chrom_name(c) in cls.reference_genomes[g]["chromosomes"])) and (
                        not cls.is_mt_chrom(c)):
                    checked = True
                    if c in cls.reference_genomes[g]["chromosomes"]:
                        found = found and (cls.reference_genomes[g]["chromosomes"][c][0] == l)
                    else:
                        found = found and (cls.reference_genomes[g]["chromosomes"][cls.extended_chrom_name(c)][0] == l)
            if checked and found:
                cls.detected_genome = g
                return g
        return None

def load_reference_genomes(cls, filename):
        _logger.info("Reading configuration file '%s'." % filename)
        exec(open(filename).read(), globals())
        for g in import_reference_genomes:
            _logger.info("Importing reference genome data: '%s'." % g)
            cls.reference_genomes[g] = import_reference_genomes[g]

def suffix_rd_flag(flags):
        s = ""
        if flags & FLAG_AT_CORR:
            s += "_AT"
        if flags & FLAG_GC_CORR:
            s += "_GC"
        if flags & FLAG_USEMASK:
            s += "_mask"
        return s

def suffix_snp_flag(flags):
        s = ""
        if flags & FLAG_USEMASK:
            s += "_mask"
        if flags & FLAG_USEID:
            s += "_id"
        if flags & FLAG_USEHAP:
            s += "_hap"
        return s

def suffix_flag(flags):
        s = ""
        if flags & FLAG_AUTO:
            s += "_auto"
        if flags & FLAG_SEX:
            s += "_sex"
        if flags & FLAG_MT:
            s += "_mt"
        if flags & FLAG_GC_CORR:
            s += "_GC"
        return s

def signal_name(self, chr_name, bin_size, signal, flags=0, name=''):
        if signal in self.signals:
            try:
                return self.signals[signal] % {"chr": chr_name, "bin_size": bin_size,
                                               "rd_flag": self.suffix_rd_flag(flags),
                                               "snp_flag": self.suffix_snp_flag(flags), "flag": self.suffix_flag(flags),
                                               "name": name}
            except TypeError:
                return None
        else:
            return None

def __init__(self, filename, ro=False, buffer=False, create=True):
        Signals.__init__(self)
        self.filename = filename
        self.file = None
        _logger.debug("Opening h5 file '%s'" % self.filename)
        if ro:
            try:
                if buffer:
                    with open(filename, 'rb') as f:
                        self.bytesio = io.BytesIO(f.read())
                    self.file = h5py.File(self.bytesio, "r")
                else:
                    self.file = h5py.File(filename, "r")
                _logger.debug("File '%s' successfully opened in read-only mode." % self.filename)
            except IOError:
                _logger.error("Unable to open file %s!" % filename)
                exit(0)
        elif os.path.exists(filename):
            try:
                self.file = h5py.File(filename, "r+")
                _logger.debug("File '%s' successfully opened." % self.filename)
            except IOError:
                _logger.error("Unable to open file %s!" % filename)
                exit(0)
        elif create:
            try:
                self.file = h5py.File(filename, "w")
                now = datetime.datetime.now()
                # Meta data
                self.add_meta_attribute('Version', __version__)
                self.add_meta_attribute('Date', now.strftime("%Y-%m-%d %H:%M"))
                _logger.debug("File '%s' successfully created." % self.filename)
            except IOError:
                _logger.error("Unable to create file %s!" % filename)
                exit(0)
        else:
            _logger.error("File %s is missing!" % filename)
            exit(0)

def chromosomes_bin_sizes_with_signal(self, signal, flags=0, name=''):
        # search_string = "^" + self.signal_name("(.[^_]*)", 17110806, signal, flags, name) + "$"
        search_string = "^" + self.signal_name("(.*)", 17110806, signal, flags, name) + "$"
        search_string = search_string.replace("17110806", "(.[0-9]*)")
        chrs_bss = []
        for key in self.file.keys():
            res = re.findall(search_string, key)
            if len(res) > 0:
                chrs_bss.append(res[0])
        if signal == "SNP likelihood":
            chrs_bss = list(map(lambda x:(x[0].replace("half_",""), x[1]), chrs_bss))
        return chrs_bss

def signal_exists(self, chr_name, bin_size, signal, flags=0, name=''):
        signame = self.signal_name(chr_name, bin_size, signal, flags, name)
        if not signame:
            return False
        if signal == "SNP likelihood":
            signame_half = self.signal_name(chr_name, bin_size, "SNP likelihood half", flags, name)
            return (signame in self.file) or (signame_half in self.file)
        else:
            return signame in self.file

def create_signal(self, chr_name, bin_size, signal, data, flags=0, name=''):
        signame = self.signal_name(chr_name, bin_size, signal, flags, name)
        if not signame:
            return None
        if signame in self.file:
            del self.file[signame]
        ds = self.file.create_dataset(signame, data.shape, dtype=str(data.dtype), compression="gzip",
                                      compression_opts=9, data=data)
        self._flush()
        return ds

def update_signal(self, chr_name, bin_size, signal, data, flags=0, name=''):
        signame = self.signal_name(chr_name, bin_size, signal, flags, name)
        if not signame:
            return None
        if not (signame in self.file):
            _logger.warning("Signal %s does not exist in file %s!" % (signame, self.filename))
            return None
        self.file[signame] = data
        self._flush()
        return self.file[signame]

def get_signal(self, chr_name, bin_size, signal, flags=0, name=''):
        signame = self.signal_name(chr_name, bin_size, signal, flags, name)
        if not signame:
            return None

        if signal=="SNP likelihood":
            signame_half = self.signal_name(chr_name, bin_size, "SNP likelihood half", flags, name)
            if signame_half in self.file:
                x=np.array(self.file[signame_half])
                return  np.concatenate((x,np.flip(x[:,:-1],axis=1)),axis=1)

        if not (signame in self.file):
            _logger.debug("Signal '%s' does not exist in file '%s'!" % (signame, self.filename))
            return []
        return np.array(self.file[signame])

def gc_info(self, stdout=False):
        ret = {}
        gc_chrom = sorted(self.gc_chromosomes(), key=lambda x: (len(x), x))
        if len(gc_chrom) > 0:
            if stdout:
                print("Contig\tLength\tGC\tGC[%]\tAT\tAT[%]\tN\tN[%]")
            for c in gc_chrom:
                gcat = self.get_signal(c, None, "GC/AT")
                gc, at = gc_at_decompress(gcat)
                l = len(gc) * 100
                tgc = sum(gc)
                tac = sum(at)
                ret[c] = [l, tgc, 100 * tgc / l, tac, 100 * tac / l, l - tac - tgc, 100 * (l - tac - tgc) / l]
                if stdout:
                    print("%s\t%d\t%d\t%.2f\t%d\t%.2f\t%d\t%.2f" % tuple([c] + ret[c]))
        return ret

def ls(self):
        print("Filename '%s'" % self.filename)
        print("-----------" + "-" * len(self.filename))

        parameter_list = ['Date', 'Version']
        if parameter_list and self.file.attrs.keys():
            date = self.file.attrs['Date']
            version = self.file.attrs['Version']
            print("File created: {} using CNVpytor ver {}\n".format(date, version))

        print("Chromosomes with RD signal: " + ", ".join(self.rd_chromosomes()))
        print()
        print("Chromosomes with SNP signal: " + ", ".join(self.snp_chromosomes()))
        print()
        if self.signal_exists(None, None, "reference genome") and self.signal_exists(None, None, "use reference"):
            rg_name = np.array(self.get_signal(None, None, "reference genome")).astype("str")[0]
            print("Using reference genome: " + rg_name + " [ ", end='')
            if rg_name in Genome.reference_genomes:
                rg_use = self.get_signal(None, None, "use reference")
                if "gc_file" in Genome.reference_genomes[rg_name] and rg_use[0] == 1:
                    print("GC: yes, ", end='')
                else:
                    print("GC: no, ", end='')
                if "mask_file" in Genome.reference_genomes[rg_name] and rg_use[1] == 1:
                    print("mask: yes ]")
                else:
                    print("mask: no ]")
        else:
            print("Reference genome is not set.")
        print()

        chr_bs = self.chromosomes_bin_sizes_with_signal("RD")
        chrs = {}
        bss = []
        for c, b in chr_bs:
            if c not in chrs:
                chrs[c] = []
            chrs[c].append(int(b))
            if int(b) not in bss:
                bss.append(int(b))

        print("Chromosomes with RD histograms [bin sizes]: " + ", ".join(chrs.keys()) + " " + str(sorted(bss)))
        print()
        chr_bs = self.chromosomes_bin_sizes_with_signal("SNP likelihood", FLAG_USEMASK)
        chrs = {}
        bss = []
        for c, b in chr_bs:
            if c not in chrs:
                chrs[c] = []
            chrs[c].append(int(b))
            if int(b) not in bss:
                bss.append(int(b))

        print("Chromosomes with SNP histograms [bin sizes]: " + ", ".join(chrs.keys()) + " " + str(sorted(bss)))
        print()
        chr_len = list(np.array(self.get_signal(None, None, "chromosome lengths")).astype("str"))
        chr_len = dict(zip(chr_len[::2], chr_len[1::2]))
        print("Chromosome lengths: " + ", ".join([str(cc)+": "+str(ll) for cc, ll in chr_len.items()]))

def save_root_trees(root_filename):
        try:
            import ROOT
        except ImportError:
            logging.warning("ROOT package is not installed - root file not saved!")
        else:
            _logger.debug(root_filename, ROOT.__version__)

def add_rd_chromosome(self, chr_name):
        if not (chr_name in self.rd_chromosomes()):
            rd_chroms = self.rd_chromosomes()
            rd_chroms.append(chr_name)
            self.create_signal(None, None, "RD chromosomes", np.array([np.bytes_(x) for x in rd_chroms]))
            _logger.debug("Chromosome '%s' added to 'RD chromosomes' list" % chr_name)

def save_snp(self, chr_name, pos, ref, alt, nref, nalt, gt, flag, qual, update=False, callset=None,
        if callset is None:
            if update:
                _logger.info("Updating SNP data for chromosome '%s'. Number of variants: %d." % (chr_name, len(pos)))
            else:
                _logger.info("Saving SNP data for chromosome '%s'. Number of variants: %d." % (chr_name, len(pos)))
        else:
            if update:
                _logger.info("Updating somatic '%s' SNV data for chromosome '%s'. Number of variants: %d." % (
                    callset, chr_name, len(pos)))
            else:
                _logger.info("Saving somatic '%s' SNV data for chromosome '%s'. Number of variants: %d." % (
                    callset, chr_name, len(pos)))
        snp_pos, snp_desc, snp_counts, snp_qual = snp_compress(pos, ref, alt, nref, nalt, gt, flag, qual)
        rd_name = self.rd_chromosome_name(chr_name)
        if not update and not (rd_name is None):
            if rd_name == chr_name:
                _logger.info("Detecting RD data in file '%s' for the same chromosome." % self.filename)
            else:
                _logger.info(
                    "Detecting RD data in file '%s' for the same chromosome with different name '%s'. RD name will be used." % (
                        self.filename, rd_name))
                chr_name = rd_name
        if not self.is_chromosome_length_set(chr_name):
            if chromosome_length is not None:
                self.set_chromosome_length(chr_name, chromosome_length)
            elif chromosome_length is None:
                self.set_chromosome_length(chr_name, pos[-1] + 1)

        if callset is None:
            self.create_signal(chr_name, None, "SNP pos", snp_pos)
            self.create_signal(chr_name, None, "SNP desc", snp_desc)
            self.create_signal(chr_name, None, "SNP counts", snp_counts)
            self.create_signal(chr_name, None, "SNP qual", snp_qual)
        else:
            self.create_signal(chr_name, None, "somatic SNP pos", snp_pos, name=callset)
            self.create_signal(chr_name, None, "somatic SNP desc", snp_desc, name=callset)
            self.create_signal(chr_name, None, "somatic SNP counts", snp_counts, name=callset)
            self.create_signal(chr_name, None, "somatic SNP qual", snp_qual, name=callset)
        if not (chr_name in self.snp_chromosomes()):
            snp_chroms = self.snp_chromosomes()
            snp_chroms.append(chr_name)
            self.create_signal(None, None, "SNP chromosomes", np.array([np.bytes_(x) for x in snp_chroms]))

def rd_chromosome_name(self, name):
        rdcs = self.rd_chromosomes()
        if name in rdcs:
            return name
        if Genome.extended_chrom_name(name) in rdcs:
            return Genome.extended_chrom_name(name)
        if Genome.canonical_chrom_name(name) in rdcs:
            return Genome.canonical_chrom_name(name)
        for rdc in rdcs:
            if Genome.canonical_chrom_name(name) == Genome.canonical_chrom_name(rdc):
                return rdc
        return None

def snp_chromosome_name(self, name):
        snpcs = self.snp_chromosomes()
        if name in snpcs:
            return name
        if Genome.extended_chrom_name(name) in snpcs:
            return Genome.extended_chrom_name(name)
        if Genome.canonical_chrom_name(name) in snpcs:
            return Genome.canonical_chrom_name(name)
        for snpc in snpcs:
            if Genome.canonical_chrom_name(name) == Genome.canonical_chrom_name(snpc):
                return snpc
        return None

def get_chromosome_lengths(self):
        chr_len = list(np.array(self.get_signal(None, None, "chromosome lengths")).astype("str"))
        chr_len = list(zip(chr_len[::2], map(int, chr_len[1::2])))
        return chr_len_(x) for s in chr_len.items() for x in s]))

def rd_normal_level(self, bin_size, flags=0):
        if self.signal_exists(None, bin_size, "RD level", flags):
            return tuple(self.get_signal(None, bin_size, "RD level", flags))
        if self.signal_exists(None, bin_size, "RD stat", FLAG_AUTO | flags):
            stat = self.get_signal(None, bin_size, "RD stat", FLAG_AUTO | flags)
        elif self.signal_exists(None, bin_size, "RD stat", FLAG_SEX | flags):
            stat = self.get_signal(None, bin_size, "RD stat", FLAG_SEX | flags)
        else:
            return 0, 0

        return stat[4], stat[5]

def save_calls(self, chr_name, bin_size, signal, calls, flags):
        keys = ["type", "start", "end", "size", "cnv", "p_val", "p_val_2", "p_val_3", "p_val_4", "Q0", "pN", "dG"]
        if signal == "calls combined" or signal == "calls baf":
            keys = ["type", "start", "end", "size", "cnv", "p_val", "lh_del", "lh_loh", "lh_dup", "Q0", "bins", "baf",
                    "rd_p_val", "baf_p_val", "segment", "hets", "homs", "pN", "pNS", "pP"]
        data = []
        for call in calls:
            item = [len(keys)] + [call[key] for key in keys]
            if "models" in call:
                for model in call["models"]:
                    item.extend(model)
            data.append(item)
        data2 = np.array(data, dtype=np.double)
        x = self.create_signal(chr_name, bin_size, signal, data2, flags=flags)

def read_calls(self, chr_name, bin_size, signal, flags):
        data = self.get_signal(chr_name, bin_size, signal, flags=flags)
        keys = ["type", "start", "end", "size", "cnv", "p_val", "p_val_2", "p_val_3", "p_val_4", "Q0", "pN", "dG"]
        if signal in {"calls combined", "calls baf"}:
            keys = ["type", "start", "end", "size", "cnv", "p_val", "lh_del", "lh_loh", "lh_dup", "Q0", "bins", "baf",
                    "rd_p_val", "baf_p_val", "segment", "hets", "homs", "pN", "pNS", "pP"]
        calls = []
        for item in data:
            call = {}
            nkeys = int(item[0])
            for ix in range(1, nkeys + 1):
                call[keys[ix - 1]] = item[ix]

            if len(item) > (nkeys + 1):
                call["models"] = []
                for i in range((len(item) - nkeys - 1) // 5):
                    call["models"].append(list(item)[nkeys + 1 + 5 * i:nkeys + 1 + 5 * (i + 1)])
            calls.append(call)
        return calls

def print_meta_attribute(self):
        print()
        print("Filename '%s'" % self.filename)
        print("-----------" + "-" * len(self.filename))
        for attribute, value in self.file.attrs.items():
            print("{}: {}".format(attribute, value))

def rd(self, bamfiles, chroms=[], reference_filename=False, overwrite=False):
        for bf in bamfiles:
            self._read_bam(bf, chroms, reference_filename=reference_filename, overwrite=overwrite)
            self.io.add_meta_attribute("BAM", bf)

        if self.io.signal_exists(None, None, "reference genome"):
            rg_name = np.array(self.io.get_signal(None, None, "reference genome")).astype("str")[0]
            if "mask_file" in Genome.reference_genomes[rg_name]:
                _logger.info("Strict mask for reference genome '%s' found in database." % rg_name)
                self.io_mask = IO(Genome.reference_genomes[rg_name]["mask_file"], ro=True)
            if "gc_file" in Genome.reference_genomes[rg_name]:
                _logger.info("GC content for reference genome '%s' found in database." % rg_name)
                self.io_gc = IO(Genome.reference_genomes[rg_name]["gc_file"], ro=True)
                self.rd_stat()

def vcf(self, vcf_files, chroms=[], sample='', no_counts=False, ad_tag="AD", gt_tag="GT", filter=True,
        for vcf_file in vcf_files:
            self._read_vcf(vcf_file, chroms, sample, no_counts=no_counts, ad_tag=ad_tag, gt_tag=gt_tag, filter=filter,
                           callset=callset, use_index=use_index)
            self.io.add_meta_attribute("VCF", vcf_file)

def rd_from_vcf(self, vcf_file, chroms=[], sample='', ad_tag="AD", dp_tag="DP", use_index=False):
        vcff = Vcf(vcf_file)
        chrs = [c for c in vcff.get_chromosomes() if len(chroms) == 0 or c in chroms]def save_data(chr, rd_p, rd_u):
            if (len(chroms) == 0 or chr in chroms) and (not rd_p is None) and (len(rd_p) > 0):
                self.io.save_rd(chr, rd_p, rd_u, chromosome_length=vcff.lengths[chr])

        if use_index:
            count = 0
            for c in chrs:
                _logger.info("Reading variant data for chromosome %s" % c)

                rd_p, rd_u = vcff.read_chromosome_rd(c, sample, ad_tag=ad_tag, dp_tag=dp_tag)
                if not rd_p is None and len(rd_p) > 0:
                    self.io.save_rd(chr, rd_p, rd_u, chromosome_length=vcff.lengths[chr])
                    count += 1
            self.io.add_meta_attribute("RD from VCF", vcf_file)
            return count
        else:
            count = vcff.read_all_rd(save_data, sample, ad_tag=ad_tag, dp_tag=dp_tag)
            self.io.add_meta_attribute("RD from VCF", vcf_file)
            return count

def pileup(self, bamfiles, chroms=[], reference_filename=False):
        chrs = [c for c in self.io.snp_chromosomes() if (len(chroms) == 0 or c in chroms)]

        pos, ref, alt, nref, nalt, gt, flag, qual = {}, {}, {}, {}, {}, {}, {}, {}
        for c in chrs:
            _logger.info("Decompressing and setting all SNP counts to zero for chromosome '%s'." % c)
            pos[c], ref[c], alt[c], nref[c], nalt[c], gt[c], flag[c], qual[c] = self.io.read_snp(c)
            nref[c] = [0] * len(nref[c])
            nalt[c] = [0] * len(nalt[c])
        for bf in bamfiles:
            self._pileup_bam(bf, chrs, pos, ref, alt, nref, nalt, reference_filename=reference_filename)

        for c in chrs:
            _logger.info("Saving SNP data for chromosome '%s' in file '%s'." % (c, self.io.filename))
            self.io.save_snp(c, pos[c], ref[c], alt[c], nref[c], nalt[c], gt[c], flag[c], qual[c])

def rd_from_snp(self, chroms=[], use_mask=True, use_id=False, callset=None, s_bin_size=10000):
        chromosomes = [c for c in self.io.snp_chromosomes() if (len(chroms) == 0 or c in chroms)]
        snp_mask_chromosomes = {}
        for c in self.io_mask.mask_chromosomes():
            snp_name = self.io.snp_chromosome_name(c)
            if snp_name is not None:
                snp_mask_chromosomes[snp_name] = c

        for c in chromosomes:
            _logger.info("Calculating RD signal for chromosome '%s' using SNP counts." % c)
            pos, ref, alt, nref, nalt, gt, flag, qual = self.io.read_snp(c, callset=callset)
            n = self.io.get_chromosome_length(c) // 100 + 1
            rd = np.zeros(n)
            ncg = self.io.get_chromosome_length(c) // s_bin_size + 1
            rdcg = np.zeros(ncg)
            rdc = np.zeros(ncg)
            for p, c1, c2, f in zip(pos, nref, nalt, flag):
                if (c1 + c2) > 0 and (not use_id or (f & 1)) and (not use_mask or (f & 2)):
                    rdcg[(p - 1) // s_bin_size] += c1 + c2
                    rdc[(p - 1) // s_bin_size] += 1
            np.seterr(divide='ignore', invalid='ignore')
            rdcg = rdcg / rdc
            for i in range(n):
                rd[i] = rdcg[i * 100 // s_bin_size]
            self.io.save_rd(c, rd, rd)

def gc(self, filename, chroms=[], make_gc_genome_file=False):
        fasta = Fasta(filename)
        chrname, chrlen = fasta.get_chr_len()
        chr_len_rdn = []
        if make_gc_genome_file:
            _logger.debug("GC data for all reference genome contigs will be read and stored in cnvnator file.")
            for (c, l) in zip(chrname, chrlen):
                chr_len_rdn.append((c, l, c))
        else:
            for (c, l) in zip(chrname, chrlen):
                rd_name = self.io.rd_chromosome_name(c)
                if len(chroms) == 0 or (rd_name in chroms) or (c in chroms):
                    if rd_name is None:
                        _logger.debug("Not found RD signal for chromosome '%s'. Skipping..." % c)
                    else:
                        _logger.debug("Found RD signal for chromosome '%s' with name '%s'." % (c, rd_name))
                        chr_len_rdn.append((c, l, rd_name))
        count = 0
        for c, l, rdn in chr_len_rdn:
            _logger.info("Reading data for chromosome '%s' with length %d" % (c, l))
            gc, at = fasta.read_chromosome_gc(c)
            if not gc is None:
                self.io.create_signal(rdn, None, "GC/AT", gc_at_compress(gc, at))
                count += 1
                _logger.info("GC data for chromosome '%s' saved in file '%s'." % (rdn, self.io.filename))
        if count > 0:
            _logger.info("Running RD statistics on chromosomes with imported GC data.")
            self.rd_stat()

def copy_gc(self, filename, chroms=[]):
        io_src = IO(filename)
        chr_rdn = []
        for c in io_src.chromosomes_with_signal(None, "GC/AT"):
            rd_name = self.io.rd_chromosome_name(c)
            if len(chroms) == 0 or (rd_name in chroms) or (c in chroms):
                if rd_name is None:
                    _logger.debug("Not found RD signal for chromosome '%s'. Skipping..." % c)
                else:
                    _logger.debug("Found RD signal for chromosome '%s' with name '%s'." % (c, rd_name))
                    chr_rdn.append((c, rd_name))
        for c, rdn in chr_rdn:
            _logger.info(
                "Copying GC data for chromosome '%s' from file '%s' in file '%s'." % (c, filename, self.io.filename))
            self.io.create_signal(rdn, None, "GC/AT", io_src.get_signal(c, None, "GC/AT").astype(dtype="uint8"))

